import { Component, type ErrorInfo, type PropsWithChildren, type ReactNode } from 'react'
import styles from './AppErrorBoundary.module.css'

type AppErrorBoundaryState = {
  hasError: boolean
  // Incrementing resetKey forces React to unmount+remount children on reset,
  // clearing the broken component state instead of re-crashing immediately.
  resetKey: number
}

export class AppErrorBoundary extends Component<PropsWithChildren, AppErrorBoundaryState> {
  state: AppErrorBoundaryState = {
    hasError: false,
    resetKey: 0,
  }

  static getDerivedStateFromError(): Partial<AppErrorBoundaryState> {
    return { hasError: true }
  }

  componentDidCatch(error: Error, info: ErrorInfo) {
    try {
      const entry = JSON.stringify({
        level: 'error',
        message: 'ui.unhandled_error',
        error: error.message,
        stack: error.stack,
        componentStack: info.componentStack,
        ts: new Date().toISOString(),
      })
      // eslint-disable-next-line no-console
      console.error(entry)
    } catch {
      // eslint-disable-next-line no-console
      console.error('Unhandled UI error:', error, info)
    }
  }

  private resetBoundary = () => {
    // Increment resetKey so React fully unmounts and remounts children,
    // clearing whatever state triggered the crash.
    this.setState((prev) => ({ hasError: false, resetKey: prev.resetKey + 1 }))
  }

  render(): ReactNode {
    if (this.state.hasError) {
      return (
        <div className={styles.shell}>
          <section className={styles.card} aria-live="assertive">
            <p className={styles.eyebrow}>UI recovery mode</p>
            <div>
              <h1 className={styles.title}>Something slipped in this workspace.</h1>
              <p className={styles.description}>
                The application hit an unexpected rendering error. Reset this view first. If the issue persists, reload the page.
              </p>
            </div>
            <div className={styles.actions}>
              <button type="button" className={styles.primaryAction} onClick={this.resetBoundary}>
                Try again
              </button>
              <button type="button" className={styles.secondaryAction} onClick={() => window.location.reload()}>
                Reload page
              </button>
            </div>
          </section>
        </div>
      )
    }

    // Keyed wrapper forces full remount of children after a reset
    return <div key={this.state.resetKey}>{this.props.children}</div>
  }
}

import {
  Component,
  type HTMLAttributes,
  type FocusEvent as ReactFocusEvent,
  type KeyboardEvent as ReactKeyboardEvent,
  type MouseEvent as ReactMouseEvent,
  type PropsWithChildren,
  type ReactNode,
  useId,
  useMemo,
} from 'react'
import { EmptyState } from './EmptyState'
import styles from './DynamicTable.module.css'

type TableRow = Record<string, unknown>

type CellAlign = 'left' | 'center' | 'right'

export type DynamicTableColumn<TRow extends TableRow> = {
  id: string
  header: ReactNode
  accessor?: keyof TRow | ((row: TRow) => unknown)
  cell?: (row: TRow, rowIndex: number) => ReactNode
  width?: string
  align?: CellAlign
  headerClassName?: string
  cellClassName?: string
}

export type DynamicTablePagination = {
  totalRows: number
  limit: number
  offset: number
  onOffsetChange: (nextOffset: number) => void
  onLimitChange?: (nextLimit: number) => void
  limitOptions?: number[]
  isFetching?: boolean
  label?: string
}

type DynamicTableProps<TRow extends TableRow> = {
  rows: TRow[]
  columns?: Array<DynamicTableColumn<TRow>>
  emptyText: string
  emptyTitle?: string
  emptyActionText?: string
  onEmptyAction?: () => void
  preferredColumns?: string[]
  className?: string
  tableClassName?: string
  containerClassName?: string
  rowKey?: (row: TRow, rowIndex: number) => string
  getRowProps?: (row: TRow, rowIndex: number) => HTMLAttributes<HTMLTableRowElement>
  onRowClick?: (row: TRow, rowIndex: number) => void
  onRowHover?: (row: TRow, rowIndex: number) => void
  getRowLabel?: (row: TRow, rowIndex: number) => string
  pagination?: DynamicTablePagination
  ariaLabel?: string
  caption?: string
  onRetry?: () => void
}

type InlineBoundaryProps = PropsWithChildren<{
  onRetry?: () => void
}>

type InlineBoundaryState = {
  hasError: boolean
}

function joinClasses(...values: Array<string | undefined | false | null>) {
  return values.filter(Boolean).join(' ')
}

function toLabel(key: string): string {
  return String(key || '')
    .replace(/[_-]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim()
    .replace(/\b\w/g, (character) => character.toUpperCase())
}

function getDetectedColumns<TRow extends TableRow>(rows: TRow[], preferredColumns: string[] = []): Array<DynamicTableColumn<TRow>> {
  const keys = new Set<string>()
  rows.forEach((row) => {
    Object.keys(row).forEach((key) => keys.add(key))
  })

  const preferred = preferredColumns.filter((key) => keys.has(key))
  const remaining = Array.from(keys)
    .filter((key) => !preferred.includes(key))
    .sort((left, right) => left.localeCompare(right))

  return [...preferred, ...remaining].map((column) => ({
    id: column,
    header: toLabel(column),
    accessor: column,
  }))
}

function formatCellValue(value: unknown): string {
  if (value == null) {
    return '-'
  }
  if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
    return String(value)
  }
  try {
    return JSON.stringify(value)
  } catch {
    return '[unavailable]'
  }
}

function resolveCellValue<TRow extends TableRow>(row: TRow, column: DynamicTableColumn<TRow>) {
  if (typeof column.accessor === 'function') {
    return column.accessor(row)
  }

  if (typeof column.accessor === 'string') {
    return row[column.accessor]
  }

  return row[column.id]
}

class InlineTableErrorBoundary extends Component<InlineBoundaryProps, InlineBoundaryState> {
  state: InlineBoundaryState = {
    hasError: false,
  }

  static getDerivedStateFromError(): InlineBoundaryState {
    return { hasError: true }
  }

  componentDidCatch(error: Error) {
    // Error is surfaced via the error boundary UI; suppress noisy console output in production
    if (import.meta.env.DEV) {
      // eslint-disable-next-line no-console
      console.error('DynamicTable render error:', error)
    }
  }

  private handleReset = () => {
    this.setState({ hasError: false })
    this.props.onRetry?.()
  }

  render() {
    if (this.state.hasError) {
      return (
        <section className={styles.errorState} role="alert" aria-live="assertive">
          <div className={styles.errorHeader}>
            <p className={styles.errorEyebrow}>Inline recovery</p>
            <h2 className={styles.errorTitle}>This table hit a rendering fault.</h2>
            <p className={styles.errorText}>
              Reset the table view first. If it fails again, refresh the workspace data and try the action again.
            </p>
          </div>
          <div className={styles.errorActions}>
            <button type="button" className={styles.primaryAction} onClick={this.handleReset}>
              Try again
            </button>
            {this.props.onRetry ? (
              <button type="button" className={styles.secondaryAction} onClick={this.props.onRetry}>
                Refresh data
              </button>
            ) : null}
          </div>
        </section>
      )
    }

    return this.props.children
  }
}

export function DynamicTable<TRow extends TableRow>({
  rows,
  columns,
  emptyText,
  emptyTitle = 'Nothing matched this view',
  emptyActionText,
  onEmptyAction,
  preferredColumns = [],
  className,
  tableClassName,
  containerClassName,
  rowKey,
  getRowProps,
  onRowClick,
  onRowHover,
  getRowLabel,
  pagination,
  ariaLabel = 'Data table',
  caption,
  onRetry,
}: DynamicTableProps<TRow>) {
  const descriptionId = useId()
  const detectedColumns = useMemo(
    () => columns ?? getDetectedColumns(rows, preferredColumns),
    [columns, preferredColumns, rows],
  )
  const totalRows = Math.max(0, pagination?.totalRows ?? rows.length)
  const limit = Math.max(1, pagination?.limit ?? rows.length ?? 1)
  const offset = Math.max(0, pagination?.offset ?? 0)
  const currentPage = totalRows === 0 ? 1 : Math.floor(offset / limit) + 1
  const totalPages = Math.max(1, Math.ceil(totalRows / limit))
  const showingFrom = totalRows === 0 ? 0 : offset + 1
  const showingTo = totalRows === 0 ? 0 : Math.min(offset + rows.length, totalRows)
  const isInteractive = Boolean(onRowClick || onRowHover)
  const summaryText = totalRows === 0
    ? 'No rows available.'
    : `Showing rows ${showingFrom} to ${showingTo} of ${totalRows}.`

  if (rows.length === 0) {
    return (
      <InlineTableErrorBoundary onRetry={onRetry}>
        <EmptyState
          title={emptyTitle}
          description={emptyText}
          actionLabel={emptyActionText}
          onAction={onEmptyAction}
          visual="table"
        />
      </InlineTableErrorBoundary>
    )
  }

  return (
    <InlineTableErrorBoundary onRetry={onRetry}>
      <div className={joinClasses(styles.shell, className)}>
        <p id={descriptionId} className={styles.srOnly}>
          {summaryText}
        </p>

        {pagination ? (
          <div className={styles.statusBar} aria-live="polite">
            <p className={styles.summary}>{summaryText}</p>
            <div className={styles.statusMeta}>
              {pagination.isFetching ? <span className={styles.fetchingBadge}>Refreshing</span> : null}
              {pagination.onLimitChange ? (
                <label>
                  <span className={styles.srOnly}>Rows per page</span>
                  <select
                    className={styles.limitSelect}
                    value={String(limit)}
                    onChange={(event) => pagination.onLimitChange?.(Number(event.target.value))}
                    aria-label="Rows per page"
                  >
                    {(pagination.limitOptions || [25, 50, 100, 250]).map((option) => (
                      <option key={option} value={option}>
                        {option} / page
                      </option>
                    ))}
                  </select>
                </label>
              ) : null}
            </div>
          </div>
        ) : null}

        <div className={joinClasses(styles.tableWrap, containerClassName)}>
          <table
            className={joinClasses(styles.table, tableClassName)}
            role="grid"
            aria-label={ariaLabel}
            aria-describedby={descriptionId}
            aria-colcount={detectedColumns.length}
            aria-rowcount={totalRows}
            aria-readonly="true"
            aria-busy={pagination?.isFetching ? 'true' : 'false'}
          >
            {caption ? <caption className={styles.srOnly}>{caption}</caption> : null}
            <colgroup>
              {detectedColumns.map((column) => (
                <col key={column.id} style={column.width ? { width: column.width } : undefined} />
              ))}
            </colgroup>
            <thead role="rowgroup">
              <tr role="row" aria-rowindex={1}>
                {detectedColumns.map((column, columnIndex) => (
                  <th
                    key={column.id}
                    role="columnheader"
                    scope="col"
                    aria-colindex={columnIndex + 1}
                    data-align={column.align || 'left'}
                    className={column.headerClassName}
                  >
                    {column.header}
                  </th>
                ))}
              </tr>
            </thead>
            <tbody role="rowgroup">
              {rows.map((row, rowIndex) => {
                const externalRowProps = getRowProps?.(row, rowIndex)
                const resolvedRowIndex = offset + rowIndex + 2
                const handleHover = () => {
                  onRowHover?.(row, rowIndex)
                }
                const handleClick = (event: ReactMouseEvent<HTMLTableRowElement>) => {
                  externalRowProps?.onClick?.(event)
                  if (!event.defaultPrevented) {
                    onRowClick?.(row, rowIndex)
                  }
                }
                const handleFocus = (event: ReactFocusEvent<HTMLTableRowElement>) => {
                  externalRowProps?.onFocus?.(event)
                  if (!event.defaultPrevented) {
                    onRowHover?.(row, rowIndex)
                  }
                }
                const handleKeyDown = (event: ReactKeyboardEvent<HTMLTableRowElement>) => {
                  externalRowProps?.onKeyDown?.(event)
                  if (event.defaultPrevented || !onRowClick) {
                    return
                  }
                  if (event.key === 'Enter' || event.key === ' ') {
                    event.preventDefault()
                    onRowClick(row, rowIndex)
                  }
                }

                return (
                  <tr
                    key={rowKey ? rowKey(row, rowIndex) : String(row.id ?? `${offset}-${rowIndex}`)}
                    {...externalRowProps}
                    role="row"
                    aria-rowindex={resolvedRowIndex}
                    aria-label={getRowLabel?.(row, rowIndex)}
                    className={joinClasses(
                      externalRowProps?.className,
                      isInteractive && styles.interactiveRow,
                    )}
                    tabIndex={isInteractive ? 0 : externalRowProps?.tabIndex}
                    onClick={handleClick}
                    onFocus={handleFocus}
                    onMouseEnter={(event) => {
                      externalRowProps?.onMouseEnter?.(event)
                      if (!event.defaultPrevented) {
                        handleHover()
                      }
                    }}
                    onKeyDown={handleKeyDown}
                  >
                    {detectedColumns.map((column, columnIndex) => (
                      <td
                        key={column.id}
                        role="gridcell"
                        aria-colindex={columnIndex + 1}
                        data-align={column.align || 'left'}
                        className={column.cellClassName}
                      >
                        {column.cell
                          ? column.cell(row, rowIndex)
                          : formatCellValue(resolveCellValue(row, column))}
                      </td>
                    ))}
                  </tr>
                )
              })}
            </tbody>
          </table>
        </div>

        {pagination && totalPages > 1 ? (
          <div className={styles.pagination} aria-label={`Pagination for ${pagination.label || 'table rows'}`}>
            <p className={styles.pageInfo}>
              Page <strong>{currentPage}</strong> of <strong>{totalPages}</strong>
            </p>
            <div className={styles.pageControls}>
              <button
                type="button"
                className={styles.pageButton}
                disabled={offset === 0}
                onClick={() => pagination.onOffsetChange(Math.max(0, offset - limit))}
              >
                Prev
              </button>
              <button
                type="button"
                className={styles.pageButton}
                disabled={offset + limit >= totalRows}
                onClick={() => pagination.onOffsetChange(offset + limit)}
              >
                Next
              </button>
            </div>
          </div>
        ) : null}
      </div>
    </InlineTableErrorBoundary>
  )
}

import { useState, useEffect } from 'react';
import * as reportService from '../../services/reportService';
import styles from './PerformanceReports.module.css';
import { 
  DonutChartWrapper, 
  BarChartWrapper, 
  CHART_COLORS,
  INCOME_COLORS
} from '../charts';

export interface MonthlyPerformance {
  month: string;
  interest_income: number;
  fee_income: number;
  penalty_income: number;
  total_income: number;
}

export interface CashFlowReport {
  total_inflow: number;
  total_outflow: number;
  net_cash_flow: number;
}

const PerformanceDashboard = () => {
  const [performance, setPerformance] = useState<MonthlyPerformance | null>(null);
  const [cashFlow, setCashFlow] = useState<CashFlowReport | null>(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState<string | null>(null);
  const [exporting, setExporting] = useState<string | null>(null);

  useEffect(() => {
    const fetchReports = async () => {
      try {
        setLoading(true);
        // Cast the results since reportService returns ReportPayload (Record<string, unknown>)
        const [perfData, flowData] = await Promise.all([
          reportService.getMonthlyPerformanceReport() as Promise<unknown>,
          reportService.getCashFlowReport() as Promise<unknown>
        ]);
        setPerformance(perfData as MonthlyPerformance);
        setCashFlow(flowData as CashFlowReport);
      } catch (err) {
                setError('Failed to load performance metrics. Please verify connectivity.');
      } finally {
        setLoading(false);
      }
    };

    fetchReports();
  }, []);

  // ── Derived Chart Data ────────────────────────────────────────────────
  const incomeCompositionData = performance ? [
    { name: 'Interest', value: performance.interest_income, color: INCOME_COLORS.interest },
    { name: 'Fees', value: performance.fee_income, color: INCOME_COLORS.fees },
    { name: 'Penalties', value: performance.penalty_income, color: INCOME_COLORS.penalties },
  ].filter(d => d.value > 0) : [];

  const cashFlowTrendData = cashFlow ? [
    { name: 'Inflow', value: cashFlow.total_inflow, color: CHART_COLORS.emerald },
    { name: 'Outflow', value: cashFlow.total_outflow, color: CHART_COLORS.red },
    { name: 'Net', value: Math.max(0, cashFlow.net_cash_flow), color: CHART_COLORS.blue },
  ] : [];

  const capitalStructureData = [
    { name: 'Active Capital', value: cashFlow?.total_inflow || 5000000, color: CHART_COLORS.emerald },
    { name: 'Allocated', value: (cashFlow?.total_outflow || 3000000) * 0.8, color: CHART_COLORS.blue },
    { name: 'Reserve', value: (cashFlow?.total_inflow || 5000000) * 0.1, color: CHART_COLORS.gold },
  ];

  const handleExport = async (endpoint: string, format: string, reportType: string) => {
    const key = `${reportType}-${format}`;
    setExporting(key);
    try {
      // reportService.downloadReport expects (path, params, format)
      await reportService.downloadReport(endpoint, {}, format as any);
    } catch (err) {
            alert(`Failed to export ${reportType}. Please try again later.`);
    } finally {
      setExporting(null);
    }
  };

  if (loading) {
    return (
      <div className={styles.container}>
        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'center', justifyContent: 'center', padding: '100px 0', gap: '16px' }}>
          <div className={styles.spinner} style={{ width: '40px', height: '40px' }}></div>
          <p style={{ color: 'var(--text-muted)', fontSize: '14px' }}>Loading insights...</p>
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className={styles.container}>
        <div style={{ padding: '32px', backgroundColor: 'var(--danger-bg)', border: '1px solid var(--danger-border)', borderRadius: '18px', color: 'var(--danger-text)', textAlign: 'center' }}>
          <h3 style={{ margin: '0 0 8px 0' }}>Data Sync Error</h3>
          <p style={{ margin: 0 }}>{error}</p>
          <button onClick={() => window.location.reload()} style={{ marginTop: '16px' }}>Retry</button>
        </div>
      </div>
    );
  }

  return (
    <div className={styles.container}>
      <header className={styles.header}>
        <div>
          <h1 className={styles.title}>Stakeholder Insights</h1>
          <p className={styles.subtitle}>Real-time financial performance and liquidity status across your portfolio.</p>
        </div>
        <div className={styles.statusTag}>
          <span className={styles.pulse}></span>
          System Live
        </div>
      </header>

      <div className={styles.grid}>
        {/* Monthly Performance Card */}
        <section className={styles.card}>
          <div className={styles.exportButtons}>
            <button 
              onClick={() => handleExport('/reports/performance/monthly', 'csv', 'monthly-performance')}
              className={styles.exportBtn}
              title="Download CSV"
            >
              {exporting === 'monthly-performance-csv' ? <div className={styles.spinner}></div> : 'CSV'}
            </button>
            <button 
              onClick={() => handleExport('/reports/performance/monthly', 'xlsx', 'monthly-performance')}
              className={styles.exportBtn}
              title="Download Excel"
            >
              {exporting === 'monthly-performance-xlsx' ? <div className={styles.spinner}></div> : 'XLSX'}
            </button>
          </div>

          <div className={styles.cardHeader}>
            <div className={styles.iconWrapper}>
              <svg className={styles.icon} width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M9 19v-6a2 2 0 00-2-2H5a2 2 0 00-2 2v6a2 2 0 002 2h2a2 2 0 002-2zm0 0V9a2 2 0 012-2h2a2 2 0 012 2v10m-6 0a2 2 0 002 2h2a2 2 0 002-2m0 0V5a2 2 0 012-2h2a2 2 0 012 2v14a2 2 0 01-2 2h-2a2 2 0 01-2-2z" /></svg>
            </div>
            <div>
              <h2 className={styles.cardTitle}>Monthly Income</h2>
              <p className={styles.cardSubtitle}>Cycle: {performance?.month || 'Current'}</p>
            </div>
          </div>

          <div className={styles.statsList}>
            <div className={styles.statItem}>
              <span className={styles.statLabel}>Interest Accrued</span>
              <span className={styles.statValue}>Ksh {(performance?.interest_income || 0).toLocaleString()}</span>
            </div>
            <div className={styles.statItem}>
              <span className={styles.statLabel}>Fee Revenue</span>
              <span className={styles.statValue}>Ksh {(performance?.fee_income || 0).toLocaleString()}</span>
            </div>
            <div className={styles.statItem}>
              <span className={styles.statLabel}>Penalty Collections</span>
              <span className={styles.statValue}>Ksh {(performance?.penalty_income || 0).toLocaleString()}</span>
            </div>

            {/* NEW: Income Composition Chart */}
            {incomeCompositionData.length > 0 && (
              <div style={{ height: 180, marginTop: 16 }}>
                <DonutChartWrapper 
                  data={incomeCompositionData} 
                  innerRadius={50} 
                  outerRadius={70} 
                />
              </div>
            )}

            <div className={styles.totalBox}>
              <div>
                <p className={styles.totalLabel}>Total Monthly Net</p>
                <h3 className={styles.totalValue}>Ksh {(performance?.total_income || 0).toLocaleString()}</h3>
              </div>
              <div className={styles.badge}>Aggregated</div>
            </div>
          </div>
        </section>

        {/* Continuous Cash Flow Card */}
        <section className={styles.cardDark}>
          <div className={styles.exportButtons}>
            <button 
              onClick={() => handleExport('/reports/performance/cashflow', 'csv', 'cashflow-status')}
              className={styles.exportBtnDark}
            >
              {exporting === 'cashflow-status-csv' ? <div className={styles.spinner}></div> : 'CSV'}
            </button>
            <button 
              onClick={() => handleExport('/reports/performance/cashflow', 'xlsx', 'cashflow-status')}
              className={styles.exportBtnDark}
            >
              {exporting === 'cashflow-status-xlsx' ? <div className={styles.spinner}></div> : 'XLSX'}
            </button>
          </div>

          <div className={styles.cardHeader}>
            <div className={styles.iconWrapperDark}>
              <svg className={styles.icon} width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.402 2.599 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.402-2.599-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
            </div>
            <div>
              <h2 className={styles.cardTitleDark}>Cash Flow Status</h2>
              <p className={styles.cardSubtitle}>Lifetime Continuous</p>
            </div>
          </div>

          <div className={styles.statsList}>
            <div className={styles.statItemDark}>
              <div style={{ width: '100%' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                  <span className={styles.statLabelDark}>Total Inflow</span>
                  <span className={styles.statValueDark}>Ksh {(cashFlow?.total_inflow || 0).toLocaleString()}</span>
                </div>
                <div className={styles.progressBar}>
                  <div className={styles.progressFill} style={{ width: '100%' }}></div>
                </div>
              </div>
            </div>

            <div className={styles.statItemDark}>
              <div style={{ width: '100%' }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '4px' }}>
                  <span className={styles.statLabelDark}>Total Outflow</span>
                  <span className={styles.statValueNegative}>-Ksh {(cashFlow?.total_outflow || 0).toLocaleString()}</span>
                </div>
                <div className={styles.progressBar}>
                  <div className={styles.progressFillDanger}></div>
                </div>
              </div>
            </div>

            {/* NEW: Cash Flow Bar Chart */}
            <div style={{ height: 160, marginTop: 8 }}>
               <BarChartWrapper 
                  data={cashFlowTrendData} 
                  xKey="name" 
                  yKey="value" 
               />
            </div>

            <div className={styles.netPositionBox}>
              <div>
                <p className={styles.totalLabel}>Net Cash Position</p>
                <h3 className={styles.totalValue} style={{ color: Number(cashFlow?.net_cash_flow) >= 0 ? 'var(--accent)' : 'var(--danger-text)' }}>
                  Ksh {(cashFlow?.net_cash_flow || 0).toLocaleString()}
                </h3>
              </div>
              <div className={styles.netIcon}>
                <svg className={styles.icon} width="20" height="20" fill="none" viewBox="0 0 24 24" stroke="currentColor">
                  {Number(cashFlow?.net_cash_flow) >= 0 
                    ? <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6" />
                    : <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={3} d="M13 17h8m0 0v-8m0 8l-8-8-4 4-6-6" />
                  }
                </svg>
