}

function TenantManagementPanel() {
  const tenantsQuery = useTenants()
  const createTenantMutation = useCreateTenant()
  const updateTenantMutation = useUpdateTenant()
  const pushToast = useToastStore((state) => state.pushToast)
  const [newTenantId, setNewTenantId] = useState('')
  const [newTenantName, setNewTenantName] = useState('')
  const [createError, setCreateError] = useState<string | null>(null)

  const tenants = tenantsQuery.data?.data ?? []

  function handleCreateTenant(event: FormEvent<HTMLFormElement>) {
    event.preventDefault()
    setCreateError(null)
    const id = newTenantId.trim()
    const name = newTenantName.trim()
    if (!id || !/^[a-zA-Z0-9_-]{2,64}$/.test(id)) {
      setCreateError('ID must be 2–64 chars: letters, numbers, hyphens, underscores only.')
      return
    }
    if (!name || name.length < 2) {
      setCreateError('Name must be at least 2 characters.')
      return
    }
    createTenantMutation.mutate(
      { id, name },
      {
        onSuccess: (data) => {
          pushToast({ type: 'success', message: `Tenant "${data.tenant.id}" created.` })
          setNewTenantId('')
          setNewTenantName('')
          setCreateError(null)
        },
        onError: (error: any) => {
          const msg = error?.response?.data?.message || 'Failed to create tenant.'
          setCreateError(msg)
          pushToast({ type: 'error', message: msg })
        },
      },
    )
  }

  return (
    <section className={styles.permissionsPanel}>
      <h2>Tenant Management</h2>
      <p className={styles.muted}>
        Tenants are the top-level isolation boundary for multi-tenant deployments. Each tenant's data
        is scoped by the <code>X-Tenant-ID</code> header and enforced at the database layer via RLS.
        The <strong>default</strong> tenant cannot be suspended or deleted.
      </p>

      {/* Existing tenants */}
      <h3>Active tenants</h3>
      {tenantsQuery.isLoading ? (
        <p className={styles.muted}>Loading tenants…</p>
      ) : tenantsQuery.isError ? (
        <p className={styles.errorText}>Unable to load tenants.</p>
      ) : tenants.length === 0 ? (
        <p className={styles.muted}>No tenants found.</p>
      ) : (
        <table className={styles.table}>
          <thead>
            <tr>
              <th>Tenant ID</th>
              <th>Name</th>
              <th>Status</th>
              <th>Created</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {tenants.map((tenant) => (
              <tr key={tenant.id}>
                <td><code>{tenant.id}</code></td>
                <td>{tenant.name}</td>
                <td>
                  <span
                    style={{
                      display: 'inline-block',
                      padding: '2px 10px',
                      borderRadius: '999px',
                      fontSize: '0.8rem',
                      fontWeight: 700,
                      background:
                        tenant.status === 'active'
                          ? 'color-mix(in srgb, var(--accent) 12%, transparent)'
                          : tenant.status === 'suspended'
                            ? 'color-mix(in srgb, orange 14%, transparent)'
                            : 'color-mix(in srgb, var(--danger-bg) 60%, transparent)',
                      color:
                        tenant.status === 'active'
                          ? 'var(--accent-strong)'
                          : tenant.status === 'suspended'
                            ? '#b45309'
                            : 'var(--danger-text)',
                    }}
                  >
                    {tenant.status}
                  </span>
                </td>
                <td>{formatDisplayDate(tenant.created_at)}</td>
                <td>
                  <div style={{ display: 'flex', gap: 8 }}>
                    {tenant.id !== 'default' && tenant.status !== 'suspended' && (
                      <button
                        type="button"
                        className={styles.secondaryButton}
                        disabled={updateTenantMutation.isPending}
                        onClick={() => {
                          updateTenantMutation.mutate(
                            { tenantId: tenant.id, payload: { status: 'suspended' } },
                            {
                              onSuccess: () => pushToast({ type: 'info', message: `Tenant "${tenant.id}" suspended.` }),
                              onError: () => pushToast({ type: 'error', message: 'Failed to suspend tenant.' }),
                            },
                          )
                        }}
                      >
                        Suspend
                      </button>
                    )}
                    {tenant.id !== 'default' && tenant.status === 'suspended' && (
                      <button
                        type="button"
                        className={styles.actionButton}
                        disabled={updateTenantMutation.isPending}
                        onClick={() => {
                          updateTenantMutation.mutate(
                            { tenantId: tenant.id, payload: { status: 'active' } },
                            {
                              onSuccess: () => pushToast({ type: 'success', message: `Tenant "${tenant.id}" reactivated.` }),
                              onError: () => pushToast({ type: 'error', message: 'Failed to reactivate tenant.' }),
                            },
                          )
                        }}
                      >
                        Reactivate
                      </button>
                    )}
                  </div>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}

      {/* Create new tenant */}
      <h3 style={{ marginTop: '1.5rem' }}>Create new tenant</h3>
      <form className={styles.createForm} onSubmit={handleCreateTenant}>
        <div className={styles.createGrid}>
          <input
            className={styles.input}
            value={newTenantId}
            onChange={(e) => setNewTenantId(e.target.value)}
            placeholder="Tenant ID (e.g. acme_corp)"
            required
          />
          <input
            className={styles.input}
            value={newTenantName}
            onChange={(e) => setNewTenantName(e.target.value)}
            placeholder="Display name (e.g. Acme Corporation)"
            required
          />
        </div>
        <p className={styles.muted}>
          Tenant ID: 2–64 characters, letters / numbers / hyphens / underscores only. Cannot be changed after creation.
        </p>
        {createError ? <p className={styles.errorText}>{createError}</p> : null}
        <div className={styles.createActions}>
          <button
            type="submit"
            className={styles.actionButton}
            disabled={createTenantMutation.isPending}
          >
            {createTenantMutation.isPending ? 'Creating…' : 'Create tenant'}
          </button>
        </div>
      </form>
    </section>
  )
}

